(function(window, document){
if(window.jQuery) return;
function $(sel){
  var nodes = (typeof sel === 'string') ? document.querySelectorAll(sel) : (sel ? [sel] : []);
  var obj = Array.prototype.slice.call(nodes);
  obj.each = function(fn){ for(var i=0;i<obj.length;i++) fn.call(obj[i], obj[i], i); return obj; };
  obj.on = function(evt, fn){ obj.each(function(el){ el.addEventListener(evt, fn); }); return obj; };
  obj.click = function(fn){ return obj.on('click', fn); };
  obj.hide = function(){ obj.each(function(el){ el.style.display='none'; }); return obj; };
  obj.show = function(){ obj.each(function(el){ el.style.display=''; }); return obj; };
  obj.slideDown = obj.show; obj.slideUp = obj.hide; obj.slideToggle = function(){ obj.each(function(el){ el.style.display = (el.style.display==='none'?'':'none'); }); return obj; };
  obj.fadeIn = obj.show; obj.fadeOut = obj.hide; obj.stop = function(){ return obj; };
  obj.text = function(v){ if(v===undefined) return obj.length>0?obj[0].textContent:''; obj.each(function(el){ el.textContent = v; }); return obj; };
  obj.val = function(v){ if(v===undefined) return obj.length>0?obj[0].value:undefined; obj.each(function(el){ el.value = v; }); return obj; };
  obj.css = function(prop, val){ if(typeof prop === 'string'){ obj.each(function(el){ el.style[prop]=val; }); } else if(typeof prop === 'object'){ for(var k in prop) obj.each(function(el){ el.style[k]=prop[k]; }); } return obj; };
  obj.addClass = function(c){ obj.each(function(el){ el.classList.add(c); }); return obj; };
  obj.removeClass = function(c){ obj.each(function(el){ el.classList.remove(c); }); return obj; };
  obj.append = function(child){ obj.each(function(el){ if(typeof child === 'string') el.insertAdjacentHTML('beforeend', child); else el.appendChild(child); }); return obj; };
  obj.prepend = function(child){ obj.each(function(el){ if(typeof child === 'string') el.insertAdjacentHTML('afterbegin', child); else el.insertBefore(child, el.firstChild); }); return obj; };
  obj.empty = function(){ obj.each(function(el){ el.innerHTML=''; }); return obj; };
  obj.toggle = function(){ obj.each(function(el){ el.style.display = (el.style.display==='none'?'':'none'); }); return obj; };
  obj.scrollLeft = function(v){ if(v===undefined) return obj.length>0?obj[0].scrollLeft:0; obj.each(function(el){ el.scrollLeft = v; }); return obj; };
  obj.position = function(){ if(obj.length==0) return {left:0}; var r = obj[0].getBoundingClientRect(); return {left: r.left, top: r.top}; };
  obj.width = function(){ return obj.length>0?obj[0].getBoundingClientRect().width:0; };
  obj.height = function(){ return obj.length>0?obj[0].getBoundingClientRect().height:0; };
  return obj;
}
window.jQuery = window.$ = $;
})(window, document);
